16	```dataviewjs
17	const currentMonth = moment("<% moment(tp.file.title, 'YYYY-MMMM').format('YYYY-MM') %>-01", "YYYY-MM-DD");
18	const startWeek = currentMonth.startOf('month').format('YYYY-[W]ww');
19	const endWeek = currentMonth.endOf('month').format('YYYY-[W]ww');
20	
21	const weeks = dv.pages('#week')
22	  .where(w => w.file.name >= startWeek && w.file.name <= endWeek);
23	
24	if (weeks.length === 0) {
25	  dv.paragraph("暂无本月周数据");
26	} else {
27	  const fields = ['Health', 'Wealth', 'Relationship', 'Spirituality'];
28	  const labels = ['💚 健康', '💰 财富', '❤️ 关系', '✨ 精神'];
29	  
30	  const stats = fields.map(field => {
31	    // 收集数字类型的值
32	    const values = [];
33	    for (const w of weeks) {
34	      const v = w[field];
35	      if (typeof v === 'number' && v > 0) {
36	        values.push(v);
37	      }
38	    }
39	    const avg = values.length > 0 ? Math.round(values.reduce((a, b) => a + b, 0) / values.length) : 0;
40	    const status = avg >= 7 ? '🟢 良好' : avg >= 4 ? '🟡 一般' : '🔴 需关注';
41	    return [labels[fields.indexOf(field)], avg + '/10', status];
42	  });
43	  
44	  dv.table(["维度", "本月平均", "状态"], stats);
45	  dv.paragraph(`*基于 ${weeks.length} 周的数据汇总*`);
46	}
